SELECT direction_of_effect, COUNT(significant_risk_factor_id) AS count_of_factors
FROM significant_risk_factors
GROUP BY direction_of_effect;

SELECT description
FROM significant_risk_factors
WHERE p_value <= 0.001;

SELECT COUNT(*) AS total_versions
FROM study_versions
WHERE study_id = 1;

SELECT study_id, version_number, changes_made
FROM study_versions
WHERE version_status = 'published' AND approval_date > '2023-01-01';

SELECT COUNT(*) AS completed_studies_count
FROM studies
WHERE study_status = 'completed' AND publication_year >= strftime('%Y', 'now') - 10;

SELECT analysis_type_name
FROM analysis_types
WHERE analysis_type_id = 0;
